function commonSections(topic, notes) {
  return [
    { title: `What ${topic} covers`, body: notes.overview },
    { title: 'Situations this page is built for', items: notes.situations },
    { title: 'Documents and details to keep ready', items: notes.documents },
    { title: 'Process', steps: notes.steps || [
      { title: 'Clarify facts', body: 'Identify the exact year, state, form, portal status, transaction type and statutory deadline.' },
      { title: 'Reconcile records', body: 'Match notices, books, portal data, invoices, challans and bank entries before filing or replying.' },
      { title: 'Prepare submission', body: 'Draft the filing, response, registration application, calculation or project scope with supporting records.' },
      { title: 'Track outcome', body: 'Download acknowledgements, respond to clarifications and keep a clean record trail.' }
    ] },
    { title: 'Common mistakes', items: notes.mistakes }
  ];
}

function faqs(topic) {
  return [
    [`Who should use ${topic}?`, `Use this page if your facts match the situations above and you want to prepare a clear WorkIndex requirement before speaking to an expert.`],
    ['Can WorkIndex help me find a specialist?', 'Yes. Post the requirement with facts, documents and deadline so relevant professionals can quote with a realistic scope.'],
    ['Do I need a local expert?', 'Many tasks can be remote, but city-specific registrations, inspections, hearings, premises verification or local business context may need local support.']
  ];
}

